WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/44.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/44.0/apex.js")}

//Obtenemos el Id de la Transaccion
var idTransaccion= '{!Transaccion__c.Id}';

//Llamamos al Web Services encargado de Generar la Nota de Credito

if(confirm('¿Desea generar una Nota de Crédito?')){

	var result = sforce.apex.execute(
		"ws_GenerarNC", //Clase a Invocar
		"generarNCWithoutMinisiteDate", //Metodo a Invocar
		{idTransaccion : idTransaccion}//Parametros
	);

	var result = result[0];

	if(result.error != null){

		alert('{!$Label.Error_Crear_Nota_de_Credito}'+' '+result.error);

	}else if(result.idNC != null){

		window.location.reload();

		var url = '/'+result.idNC;

		window.open(url,'_blank');

	}

}
